using Toarnbeike.SourceGeneration.Rendering;
using Toarnbeike.Unions.SourceGenerator.Models;

namespace Toarnbeike.Unions.SourceGenerator.Rendering;

internal static class CollectionExtensionsGenerator
{
    public static string Execute(UnionModel model)
    {
        return $$"""
                 # nullable enable
                 
                 // <auto-generated>
                 //   This file was generated by Toarnbeike.Unions.SourceGenerator.
                 //   Generator: {{nameof(CollectionExtensionsGenerator)}}
                 //   Created: {{DateTime.UtcNow:u}}
                 //   This is an auto-generated file. Do not modify.
                 // </auto-generated>

                 using Toarnbeike.Unions.Generic;
                 using Toarnbeike.Unions.Generic.Extensions;
                 using {{model.Namespace}};
                 {{model.CaseUsings}}
                 namespace Toarnbeike.Unions.Nominal.Collections;
                 
                 public static class {{model.Name}}SelectExtensions
                 {
                     extension(IEnumerable<{{model.Name}}> source)
                     {
                 {{model.Cases
                     .Select(SelectCase)
                     .JoinLines()
                     .Indent(2)}}
                 {{Partition(model).Indent(2)}}
                     }
                 }
                 """;
    }

    private static string SelectCase(UnionCaseModel caseModel)
    {
        return $$"""
                 /// <summary>
                 /// Select all elements of type {{caseModel.Name}} from the collection
                 /// </summary>
                 public IEnumerable<{{caseModel.Name}}> Select{{caseModel.Name}}()
                 {
                     ArgumentNullException.ThrowIfNull(source);
                     
                     foreach (var item in source)
                     {
                         if (item.TryGet{{caseModel.Name}}(out var {{caseModel.ArgumentName}}))
                         {
                             yield return {{caseModel.ArgumentName}};
                         }
                     }
                 }
                 
                 """;
    }

    private static string Partition(UnionModel model)
    {
        return $$"""
                 /// <summary>
                 /// Partitions the {{model.Name}} collection into separate collections for each case.
                 /// </summary>
                 public ({{model.Cases.Select(caseModel => $"IReadOnlyList<{caseModel.Name}> {caseModel.Name}Set").JoinCommaSeparated()}}) Partition()
                 {
                     ArgumentNullException.ThrowIfNull(source);
                     
                 {{model.Cases
                     .Select(caseModel => $"var {caseModel.ArgumentName}Set = new List<{caseModel.Name}>();")
                     .JoinLines()
                     .Indent(1)
                 }}
                 
                     foreach (var element in source)
                     {
                         element.Switch({{model.Cases.Select(caseModel => $"{caseModel.ArgumentName}Set.Add").JoinCommaSeparated()}});
                     }
                     
                     return ({{model.Cases.Select(caseModel => $"{caseModel.ArgumentName}Set").JoinCommaSeparated()}});
                 }
                 """;
    }
}
